INSERT INTO `financial_products` VALUES ('00bb809f-5b0b-4694-8569-c4721163e66b','WLT-012','Safaricom PLC Shares','Safaricom PLC','Stock / ETF','Blue Chip Equity',1000.00,'12.0%','Open-ended','T+3 settlement','Medium-High','CMA Kenya',21,55,'Growth investors, dividend seekers','Safaricom is East Africa\'s largest company by market cap. M-Pesa ecosystem drives double-digit earnings growth. Historically pays KES 0.60-0.76 dividend per share. Buy through a licensed stockbroker.','2026-06-30 08:38:06.431000','2026-06-30 08:38:06.431000'),('05240343-2f51-48af-a9c7-d064cfa0739d','WLT-007','Old Mutual Enhanced Income','Old Mutual Investment Group','MMF','Enhanced Income',5000.00,'11.4%','Open-ended','Weekly (T+3)','Low-Medium','CMA Kenya',21,60,'Income-oriented investors','Old Mutual\'s Enhanced Income Fund invests in slightly longer-tenor government securities for a yield premium over standard MMFs. Weekly liquidity. Minimum KES 5,000.','2026-06-30 08:38:01.272000','2026-06-30 08:38:01.272000'),('05ff6976-af17-4e57-b3ee-aa3e032282bf','WLT-011','New Gold ETF (GLD)','Absa CIB / JSE','Stock / ETF','Gold ETF',5000.00,'8.5%','Open-ended','T+3 settlement','Medium-High','CMA Kenya / JSE',21,55,'Inflation hedge, diversification seekers','New Gold ETF tracks the gold spot price in KES terms. One unit = 1/100th of a troy ounce of gold. Trades on NSE. Ideal for investors seeking a hedge against KES depreciation and inflation.','2026-06-30 08:38:05.357000','2026-06-30 08:38:05.357000'),('1fbb86d7-7439-48ab-85ad-53389efee303','WLT-016','182-Day Treasury Bill','Central Bank of Kenya','Government Security','T-Bill',49680.00,'15.2%','182 days','End of tenor','Very Low','CBK',21,75,'Medium short-term government savings','Kenya 182-day T-Bill. Better yield than 91-day for slightly longer lock-in. Same minimum. Zero credit risk. Ideal for money not needed for 6 months.','2026-06-30 08:38:10.210000','2026-06-30 08:38:10.210000'),('211cd525-76b9-4c27-b422-1ee8243b73a5','WLT-003','Cytonn High Yield Fund','Cytonn Asset Management','MMF','High-Yield',10000.00,'13.8%','Open-ended','Weekly (T+5)','Medium','CMA Kenya',25,55,'Investors seeking higher short-term returns','Cytonn HYF invests in corporate bonds, real estate notes, and structured credit. Higher yield than T-Bill-backed MMFs, with commensurate credit risk. Minimum KES 10,000.','2026-06-30 08:37:57.561000','2026-06-30 08:37:57.561000'),('23832c3f-da9b-40d6-8d6e-f53bf216915e','WLT-019','Equity Bank Fixed Deposit','Equity Bank','Fixed Deposit','Term Deposit',50000.00,'9.5%','12 months','End of tenor','Very Low','CBK',18,75,'Safety-first, short-term capital preservation','Equity Bank 12-month fixed deposit. KDIC-insured up to KES 500,000. Interest paid at maturity. Good for capital that must be preserved with a guaranteed return.','2026-06-30 08:38:13.132000','2026-06-30 08:38:13.132000'),('3095e70f-04b1-46f4-b47f-4ded98ebec0d','WLT-010','Harambee Sacco Deposits','Harambee Co-op Sacco','Sacco','FOSA Fixed Deposit',10000.00,'9.5%','12 months','End of tenor','Low-Medium','SASRA',21,65,'Civil servants, NGO workers','Harambee FOSA fixed deposits earn 9-10% p.a. for 12-month tenors. Open to civil servants and the general public. Deposits are protected by DCS (Deposit Compensation Scheme).','2026-06-30 08:38:04.143000','2026-06-30 08:38:04.143000'),('49b5a19a-3c35-4c04-86ef-69fb752f77b9','WLT-006','ICEA Lion Money Market','ICEA Lion Asset Management','MMF','Money Market',1000.00,'10.3%','Open-ended','Daily (T+1)','Low','CMA Kenya',18,65,'Professionals, SME working capital','ICEA Lion MMF combines safety and liquidity for professionals managing working capital or emergency savings. Portfolio: 60% government securities, 40% bank placements.','2026-06-30 08:38:00.363000','2026-06-30 08:38:00.363000'),('5fffcdaa-e1d9-4817-bf99-c2d3be74321c','WLT-001','CIC Money Market Fund','CIC Asset Management','MMF','Money Market',1000.00,'10.2%','Open-ended','Daily (T+1)','Low','CMA Kenya',18,65,'First-time investors, emergency fund','CIC MMF is Kenya\'s most accessible money market fund. Earn daily interest on savings from KES 1,000. Backed by T-Bills, commercial paper, and bank deposits. Interest paid daily. Withdraw next business day.','2026-06-30 08:37:55.275000','2026-06-30 08:37:55.275000'),('91fc90be-723e-4d56-a793-151276f2758d','WLT-009','Mwalimu National Sacco Shares','Mwalimu National Sacco','Sacco','Share Capital',10000.00,'13.2%','Annual','Annual dividends','Medium','SASRA',25,65,'Teachers, TSC employees','Mwalimu National Sacco — Kenya\'s largest Sacco by asset base. 13-15% annual dividends on share capital. Membership open to all TSC-registered teachers. FOSA accounts earn 4% p.a. on savings.','2026-06-30 08:38:03.108000','2026-06-30 08:38:03.108000'),('96fd93f5-a58a-4141-ba38-b899f879db11','WLT-014','KCB Group Shares','KCB Group','Stock / ETF','Blue Chip Equity',1000.00,'11.5%','Open-ended','T+3 settlement','Medium-High','CMA Kenya',21,55,'Banking sector, value investors','KCB Group is Kenya\'s largest bank by assets. Strong regional footprint. DRC operations a growth catalyst. Dividend yield approximately 8-10%.','2026-06-30 08:38:08.267000','2026-06-30 08:38:08.267000'),('abc8958f-2eaa-451e-8fa4-02aa3fca3da7','WLT-002','Sanlam Money Market Fund','Sanlam Investments Kenya','MMF','Money Market',1000.00,'10.5%','Open-ended','Daily (T+1)','Low','CMA Kenya',18,65,'Conservative savers, short-term parking','Sanlam MMF offers competitive daily yields backed by a diversified portfolio of government securities and bank deposits. Minimum KES 1,000. No lock-in period. Top-10 performing MMF in Kenya.','2026-06-30 08:37:56.646000','2026-06-30 08:37:56.646000'),('af3e3d14-0c42-468e-9530-f92f074ebd45','WLT-017','364-Day Treasury Bill','Central Bank of Kenya','Government Security','T-Bill',49680.00,'15.6%','364 days','End of tenor','Very Low','CBK',21,75,'Individuals seeking best short-term government yield','Kenya 364-day T-Bill — highest yield in the T-Bill curve. 1-year lock-in. Mini