DROP TABLE IF EXISTS `parts_catalogues`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `parts_catalogues` (
  `id` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `sku` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `make` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `model` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `yearFrom` int NOT NULL,
  `yearTo` int NOT NULL,
  `engineCc` int NOT NULL,
  `batteryType` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `voltage` int NOT NULL,
  `capacityAh` int NOT NULL,
  `cca` int NOT NULL,
  `brand` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `priceKes` decimal(10,2) NOT NULL,
  `stock` int NOT NULL DEFAULT '0',
  `branchLocation` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `warrantyMonths` int NOT NULL,
  `created_at` timestamp(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6),
  `updated_at` timestamp(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6),
  PRIMARY KEY (`id`),
  UNIQUE KEY `parts_catalogues_sku_key` (`sku`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

